                          <input type="checkbox" className="h-4 w-4 rounded accent-indigo-600" checked={filterPaymentType === op} onChange={() => setFilterPaymentType(filterPaymentType === op ? 'all' : op)} />
                          {op === 'all' ? 'Todos' : op}
